import { useEffect, useRef } from "react";
import type { IrukaGame, GameRuntimeConfig } from "../core/game/types";

type Props = {
  createGame: () => IrukaGame;
  config: GameRuntimeConfig;
  className?: string;
};

/**
 * React host component for Iruka games.
 * Manages game lifecycle (init, start, pause, resume, dispose) and visibility changes.
 */
export function IrukaGameHost({ createGame, config, className }: Props) {
  const gameRef = useRef<IrukaGame | null>(null);

  useEffect(() => {
    const game = createGame();
    gameRef.current = game;

    (async () => {
      await game.onInit(config);
      await game.onStart();
    })();

    const onVis = () =>
      document.hidden ? game.onPause?.() : game.onResume?.();
    document.addEventListener("visibilitychange", onVis);

    return () => {
      document.removeEventListener("visibilitychange", onVis);
      game.onDispose?.();
      gameRef.current = null;
    };
  }, [config, createGame]);

  return <div id="game-root" className={className ?? "w-full h-full"} />;
}
