// src/core/phaser/assetManager.ts
import Phaser from "phaser";

export type ImageCandidate = {
  key: string; // key trong Phaser cache
  basePath: string; // không có extension, ví dụ "/assets/bg/home"
  exts?: string[]; // default ["avif","webp","png","jpg","jpeg"]
  crossOrigin?: "anonymous" | "use-credentials" | "";
};

export type AtlasCandidate = {
  key: string;
  imageBasePath: string; // "/assets/atlas/ui" -> ui.webp/ui.png...
  atlasJsonPath: string; // "/assets/atlas/ui.json"
  exts?: string[]; // default ["avif","webp","png"]
  crossOrigin?: "anonymous" | "use-credentials" | "";
};

export type AudioCandidate = {
  key: string;
  paths: string[]; // ví dụ ["/assets/audio/sfx.m4a","/assets/audio/sfx.ogg"]
};

export type JsonCandidate = { key: string; path: string };

export type AssetPack = {
  images?: ImageCandidate[];
  atlases?: AtlasCandidate[];
  audio?: AudioCandidate[];
  json?: JsonCandidate[];
};

export type AssetLoadProgress = {
  loaded: number;
  total: number;
  progress01: number; // 0..1
  currentKey?: string;
};

export type AssetManagerOptions = {
  /** Cho phép dùng HEAD để chọn extension tốt nhất (khuyến nghị) */
  preferNetworkProbe?: boolean; // default true
  /** timeout cho HEAD (ms) */
  probeTimeoutMs?: number; // default 1500
  /** callback progress */
  onProgress?: (p: AssetLoadProgress) => void;
  /** log debug */
  debug?: boolean;
  strict?: boolean; // ✅ NEW: thiếu asset => throw ngay
};

export class AssetManager {
  private scene: Phaser.Scene;
  private opts: Required<Omit<AssetManagerOptions, "onProgress">> & {
    onProgress?: (p: AssetLoadProgress) => void;
  };

  constructor(scene: Phaser.Scene, opts?: AssetManagerOptions) {
    this.scene = scene;
    this.opts = {
      preferNetworkProbe: opts?.preferNetworkProbe ?? true,
      probeTimeoutMs: opts?.probeTimeoutMs ?? 1500,
      debug: opts?.debug ?? false,
      strict: opts?.strict ?? false,
      onProgress: opts?.onProgress,
    };
  }

  /**
   * Load một pack và đảm bảo decode image (phần decode là “giảm giật”)
   */
  async loadPack(pack: AssetPack): Promise<void> {
    const images = pack.images ?? [];
    const atlases = pack.atlases ?? [];
    const audio = pack.audio ?? [];
    const json = pack.json ?? [];

    // 1) resolve best URLs
    const resolvedImages = await Promise.all(
      images.map((it) => this.resolveImage(it))
    );
    const resolvedAtlases = await Promise.all(
      atlases.map((it) => this.resolveAtlas(it))
    );

    // 2) queue vào Phaser Loader
    const loader = this.scene.load;

    for (const img of resolvedImages) {
      if (!this.scene.textures.exists(img.key)) {
        loader.image(img.key, img.url);
        if (img.crossOrigin != null) loader.setCORS(img.crossOrigin);
      }
    }

    for (const at of resolvedAtlases) {
      if (!this.scene.textures.exists(at.key)) {
        loader.atlas(at.key, at.imageUrl, at.atlasJsonPath);
        if (at.crossOrigin != null) loader.setCORS(at.crossOrigin);
      }
    }

    for (const a of audio) {
      if (!this.scene.cache.audio.exists(a.key)) {
        loader.audio(a.key, a.paths);
      }
    }

    for (const j of json) {
      if (!this.scene.cache.json.exists(j.key)) {
        loader.json(j.key, j.path);
      }
    }

    // 3) hook progress
    const total = resolvedImages.length + resolvedAtlases.length + audio.length;

    if (total === 0) return;

    let loadedCount = 0;
    const emit = (currentKey?: string, progress01?: number) => {
      const p01 = progress01 ?? (total ? loadedCount / total : 1);
      this.opts.onProgress?.({
        loaded: loadedCount,
        total,
        progress01: clamp01(p01),
        currentKey,
      });
    };

    loader.on(Phaser.Loader.Events.FILE_COMPLETE, (key: string) => {
      loadedCount += 1;
      emit(key);
    });

    // 4) run loader
    await new Promise<void>((resolve, reject) => {
      let firstError: any = null;

      const onFileError = (file: any) => {
        firstError ??= file;
        // đừng reject ở đây (vì complete vẫn sẽ bắn), cứ ghi lại
      };

      loader.once(Phaser.Loader.Events.FILE_LOAD_ERROR, onFileError);

      loader.once(
        Phaser.Loader.Events.COMPLETE,
        async (_ldr: any, totalComplete: number, totalFailed: number) => {
          try {
            // ✅ nếu có fail -> reject để try/catch bắt được
            if (totalFailed > 0) {
              const f = firstError;
              reject(
                new Error(
                  `ASSET_LOAD_FAIL: failed=${totalFailed}, complete=${totalComplete}, first=${
                    f?.key || "unknown"
                  } url=${f?.src || f?.url || ""}`
                )
              );
              return;
            }

            // decode images + atlas textures
            await this.decodeTextures([
              ...resolvedImages.map((i) => i.key),
              ...resolvedAtlases.map((a) => a.key),
            ]);

            emit(undefined, 1);
            resolve();
          } catch (e) {
            reject(e);
          }
        }
      );

      emit(undefined, 0);
      loader.start();
    });

    // cleanup listeners (đừng removeAllListeners bừa bãi)
    loader.off(Phaser.Loader.Events.FILE_LOAD_ERROR);
    loader.off(Phaser.Loader.Events.FILE_COMPLETE);
  }

  // ----------------- resolve URLs -----------------

  private async resolveImage(
    it: ImageCandidate
  ): Promise<{ key: string; url: string; crossOrigin?: any }> {
    const exts = it.exts ?? ["avif", "webp", "png", "jpg", "jpeg"];
    const url = await this.pickBest(`${it.basePath}`, exts);
    return { key: it.key, url, crossOrigin: it.crossOrigin };
  }

  private async resolveAtlas(it: AtlasCandidate): Promise<{
    key: string;
    imageUrl: string;
    atlasJsonPath: string;
    crossOrigin?: any;
  }> {
    const exts = it.exts ?? ["avif", "webp", "png"];
    const imageUrl = await this.pickBest(`${it.imageBasePath}`, exts);
    return {
      key: it.key,
      imageUrl,
      atlasJsonPath: it.atlasJsonPath,
      crossOrigin: it.crossOrigin,
    };
  }

  /**
   * chọn extension theo:
   * - nếu preferNetworkProbe: HEAD lần lượt -> cái nào tồn tại dùng
   * - fallback: chọn theo support (avif/webp) rồi fallback png/jpg
   */
  private async pickBest(base: string, exts: string[]): Promise<string> {
    const ordered = orderBySupport(exts);
    const tried: string[] = [];

    if (this.opts.preferNetworkProbe) {
      for (const ext of ordered) {
        const url = `${base}.${ext}`;
        tried.push(url);
        const ok = await headOk(url, this.opts.probeTimeoutMs);
        if (ok) return url;
      }

      if (this.opts.strict) {
        throw new Error(`ASSET_MISSING: ${base} (tried: ${tried.join(", ")})`);
      }

      // non-strict fallback
      return `${base}.${ordered[0]}`;
    }

    // không probe thì không thể chắc file tồn tại
    return `${base}.${ordered[0]}`;
  }

  // ----------------- decode -----------------

  /**
   * Decode texture sources để giảm giật:
   * - tạo ImageBitmap nếu browser support (nhanh)
   * - hoặc fallback: tạo <img>.decode() qua network cache (chỉ làm được khi có URL)
   *
   * Lưu ý: Phaser texture có thể chứa nhiều source (atlas)
   */
  private async decodeTextures(textureKeys: string[]): Promise<void> {
    const unique = Array.from(new Set(textureKeys));
    const tasks: Promise<void>[] = [];

    for (const key of unique) {
      const tex = this.scene.textures.get(key);
      if (!tex) continue;

      // texture source: tex.source[0].image là HTMLImageElement / HTMLCanvasElement
      const sources: any[] = (tex as any).source ?? [];
      for (const s of sources) {
        const img: any = s?.image;
        if (!img) continue;

        // already decoded?
        if ((img as any).__irukaDecoded) continue;

        tasks.push(
          decodeOne(img).then(() => {
            (img as any).__irukaDecoded = true;
          })
        );
      }
    }

    await Promise.all(tasks);
  }
}

// ---------------- utils ----------------

function clamp01(n: number) {
  return Math.max(0, Math.min(1, n));
}

function orderBySupport(exts: string[]) {
  // ưu tiên AVIF/WebP nếu support; nếu không support thì chúng sẽ rớt xuống
  const avifOk = supportsAvif();
  const webpOk = supportsWebp();

  const score = (ext: string) => {
    const e = ext.toLowerCase();
    if (e === "avif") return avifOk ? 0 : 100;
    if (e === "webp") return webpOk ? 1 : 101;
    if (e === "png") return 10;
    if (e === "jpg" || e === "jpeg") return 11;
    return 50;
  };

  return [...exts].sort((a, b) => score(a) - score(b));
}

// nhanh, không 100% tuyệt đối nhưng đủ cho runtime
function supportsWebp() {
  try {
    const c = document.createElement("canvas");
    return c.toDataURL("image/webp").startsWith("data:image/webp");
  } catch {
    return false;
  }
}

function supportsAvif() {
  // AVIF detection “đúng” thường async; bản lightweight: dùng CSS.supports nếu có
  // Đây chỉ để order; nếu probe bật thì HEAD mới là quyết định.
  try {
    // @ts-ignore
    return typeof CSS !== "undefined" &&
      CSS.supports?.("image-rendering", "auto")
      ? true
      : false;
  } catch {
    return false;
  }
}

async function headOk(url: string, timeoutMs: number): Promise<boolean> {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      method: "HEAD",
      mode: "cors",
      cache: "no-cache",
      signal: ctrl.signal,
    });
    return res.ok;
  } catch {
    return false;
  } finally {
    clearTimeout(t);
  }
}

async function decodeOne(img: any): Promise<void> {
  // HTMLImageElement has decode()
  if (typeof img.decode === "function") {
    try {
      await img.decode();
    } catch {}
    return;
  }

  // if ImageBitmap exists and source is a Blob/bitmap-capable => not available here usually
  return;
}
