/* eslint-disable @typescript-eslint/no-explicit-any */

export type SpyCategory = "sdk" | "stats" | "hub";

export type SpyRecord = {
  t: number;                 // performance.now()
  cat: SpyCategory;
  name: string;              // event name, ex: "sendEvent", "recordWrong"
  data?: any;                // payload nhỏ, đã cắt bớt
};

type SpyConfig = {
  maxRecords: number;        // tránh phình bộ nhớ
  maxJsonChars: number;      // tránh log payload quá lớn
};

const cfg: SpyConfig = {
  maxRecords: 2000,
  maxJsonChars: 4000,
};

let enabled = false;
const records: SpyRecord[] = [];

function safeCloneSmall(v: any, maxChars = cfg.maxJsonChars) {
  // clone “an toàn” và cắt bớt để khỏi vượt 16KB/đồ thị sâu
  try {
    const json = JSON.stringify(v, (_k, val) => {
      if (val instanceof Error) {
        return { name: val.name, message: val.message, stack: val.stack };
      }
      return val;
    });
    if (json.length <= maxChars) return JSON.parse(json);
    return { truncated: true, preview: json.slice(0, maxChars) + "…" };
  } catch {
    return { unserializable: true, preview: String(v) };
  }
}

export function spyPush(cat: SpyCategory, name: string, data?: any) {
  if (!enabled) return;
  records.unshift({
    t: performance.now(),
    cat,
    name,
    data: data === undefined ? undefined : safeCloneSmall(data),
  });
  if (records.length > cfg.maxRecords) records.length = cfg.maxRecords;
}

export const __testSpy = {
  enable() { enabled = true; },
  disable() { enabled = false; },
  isEnabled() { return enabled; },
  reset() { records.length = 0; },
  getRecords() { return records.map(r => ({...r, data: r.data})); },
  getSummary() {
    const out: Record<string, number> = {};
    for (const r of records) {
      const k = `${r.cat}:${r.name}`;
      out[k] = (out[k] || 0) + 1;
    }
    return out;
  },
  setConfig(patch: Partial<SpyConfig>) {
    if (typeof patch.maxRecords === "number" && patch.maxRecords > 0) cfg.maxRecords = Math.floor(patch.maxRecords);
    if (typeof patch.maxJsonChars === "number" && patch.maxJsonChars > 100) cfg.maxJsonChars = Math.floor(patch.maxJsonChars);
  }
} as const;
