export enum ExerciseType {
  NURSERY_RHYME = "NURSERY_RHYME",
  COUNTING = "COUNTING",
  SPELLING = "SPELLING",
}

/**
 * StartSession: game KHÔNG cần truyền metadata.
 * SDK sẽ lấy từ INIT context hoặc defaultMeta.
 */
export interface StartSessionRequest {
  /** override if needed (usually not) */
  gameSessionId?: string;   // default = sdkContext.sessionId
  gameId?: string;          // default = sdkContext.gameId
  lessonId?: string;        // default = sdkContext.lessonId
  gameVersion?: string;     // default = sdkContext.gameVersion

  testmode?: boolean;
}

export interface StartSessionResponse {
  sessionId: string;
  allowPlay: boolean;
  index: number;
  quotaRemaining: number;
  message?: string;
  testMode?: boolean;
  debugInfo?: any;
}

export interface SubmitAnswerRequest {
  /**
   * Optional:
   * - Nếu không truyền, SDK sẽ dùng "voiceSessionId" mới nhất đã tạo từ StartSession()
   */
  sessionId?: string;

  audioFile: File | Blob;
  questionIndex: number; // 1-based
  targetText: string | object;
  durationMs: number;
  exerciseType: ExerciseType;
  testmode?: boolean;
}

export interface SubmitAnswerResponse {
  score: number;
  attitude_level: string;
  feedback: string;
  testMode?: boolean;
  debugInfo?: any;
}

export interface EndSessionRequest {
  sessionId?: string;
  totalQuestionsExpect: number;
  isUserAborted: boolean;
  testmode?: boolean;
}

export interface EndSessionResponse {
  status: string;
  finalScore: number;
  completionPct: number;
  quotaDeducted: boolean;
  violations?: any;
  testMode?: boolean;
  debugInfo?: any;
}

export interface ApiError {
  detail: string;
}
