import { getSdkContext } from "../shared/sdkContext";
import {
  type ApiError,
  type StartSessionRequest,
  type StartSessionResponse,
  type SubmitAnswerRequest,
  type SubmitAnswerResponse,
  type EndSessionRequest,
  type EndSessionResponse,
} from "./types";

const DEFAULT_BASE_URL = "https://iruka-api-1037337851453.asia-southeast1.run.app";
const DEFAULT_API_VERSION = "v1";

export type HeadersProvider =
  | Record<string, string>
  | (() => Record<string, string> | Promise<Record<string, string>>);

export type VoiceDefaultMeta = {
  gameSessionId?: string;
  gameId?: string;
  lessonId?: string;
  gameVersion?: string;
};

export interface VoiceSessionConfig {
  baseUrl?: string;
  apiVersion?: string;
  timeoutMs?: number;
  testMode?: boolean;
  headers?: HeadersProvider;

  /** dùng cho standalone/test nếu không có INIT */
  defaultMeta?: VoiceDefaultMeta;
}

export class VoiceApiError extends Error {
  readonly status: number;
  readonly endpoint: string;
  readonly detail?: string;

  constructor(args: { status: number; endpoint: string; message: string; detail?: string }) {
    super(args.message);
    this.name = "VoiceApiError";
    this.status = args.status;
    this.endpoint = args.endpoint;
    this.detail = args.detail;
  }
}

function withTimeoutSignal(timeoutMs: number): { signal: AbortSignal; cancel: () => void } {
  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), timeoutMs);
  return { signal: controller.signal, cancel: () => clearTimeout(t) };
}

async function resolveHeaders(headers?: HeadersProvider): Promise<Record<string, string>> {
  if (!headers) return {};
  if (typeof headers === "function") return await headers();
  return headers;
}

async function safeReadErrorDetail(res: Response): Promise<{ detail?: string; rawText?: string }> {
  const contentType = res.headers.get("content-type") || "";
  try {
    if (contentType.includes("application/json")) {
      const j = (await res.json()) as Partial<ApiError> & Record<string, any>;
      return { detail: typeof j.detail === "string" ? j.detail : JSON.stringify(j) };
    }
    const text = await res.text();
    return { rawText: text };
  } catch {
    return {};
  }
}

function resolveStartMeta(req: StartSessionRequest, defaultMeta?: VoiceDefaultMeta) {
  const ctx = getSdkContext();
  return {
    gameSessionId: req.gameSessionId ?? ctx.sessionId ?? defaultMeta?.gameSessionId,
    gameId: req.gameId ?? ctx.gameId ?? defaultMeta?.gameId,
    lessonId: req.lessonId ?? ctx.lessonId ?? defaultMeta?.lessonId,
    gameVersion: req.gameVersion ?? ctx.gameVersion ?? defaultMeta?.gameVersion,
  };
}

export class VoiceSessionClient {
  private baseUrl: string;
  private apiVersion: string;
  private timeoutMs: number;
  private defaultTestMode: boolean;
  private headers?: HeadersProvider;
  private defaultMeta?: VoiceDefaultMeta;

  /** lưu voice sessionId gần nhất */
  private lastVoiceSessionId: string | null = null;

  constructor(config: VoiceSessionConfig = {}) {
    this.baseUrl = config.baseUrl || DEFAULT_BASE_URL;
    this.apiVersion = config.apiVersion || DEFAULT_API_VERSION;
    this.timeoutMs = config.timeoutMs ?? 60_000;
    this.defaultTestMode = config.testMode ?? false;
    this.headers = config.headers;
    this.defaultMeta = config.defaultMeta;
  }

  /** để test/dev nếu muốn set thẳng */
  setLastVoiceSessionId(id: string | null) {
    this.lastVoiceSessionId = id;
  }

  getLastVoiceSessionId() {
    return this.lastVoiceSessionId;
  }

  async startSession(request: StartSessionRequest = {}): Promise<StartSessionResponse> {
    const testmode = request.testmode ?? this.defaultTestMode;
    const endpoint = `/api/${this.apiVersion}/voice-sessions/start?testmode=${testmode}`;
    const url = `${this.baseUrl}${endpoint}`;

    const meta = resolveStartMeta(request, this.defaultMeta);

    // Nếu backend bạn sửa để không cần mấy meta này nữa thì có thể bỏ check.
    // Mình vẫn giữ check nhẹ cho PROD để khỏi gọi thiếu context mà fail khó hiểu.
    if (!meta.gameId || !meta.gameVersion) {
      if (testmode) {
        meta.gameId ??= "local-game";
        meta.gameVersion ??= "0.0.0";
      } else {
        throw new Error(
          `Voice startSession missing meta (gameId/gameVersion). ` +
            `Call configureSdkContext({ fallback: ... }) or run inside Hub INIT.`
        );
      }
    }

    const extraHeaders = await resolveHeaders(this.headers);
    const { signal, cancel } = withTimeoutSignal(this.timeoutMs);

    try {
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...extraHeaders,
        },
        body: JSON.stringify({
          gameSessionId: meta.gameSessionId,
          gameId: meta.gameId,
          lessonId: meta.lessonId,
          gameVersion: meta.gameVersion,
        }),
        signal,
      });

      if (!res.ok) {
        const err = await safeReadErrorDetail(res);
        throw new VoiceApiError({
          status: res.status,
          endpoint,
          detail: err.detail,
          message: `Start session failed (${res.status})${err.detail ? `: ${err.detail}` : ""}`,
        });
      }

      const data = (await res.json()) as StartSessionResponse;

      // ✅ lưu lại để Submit/End khỏi cần truyền sessionId
      this.lastVoiceSessionId = data.sessionId;

      return data;
    } finally {
      cancel();
    }
  }

  private resolveVoiceSessionId(explicit?: string) {
    const id = explicit ?? this.lastVoiceSessionId;
    if (!id) {
      throw new Error(
        `Missing voice sessionId. Call StartSession() first (or pass sessionId explicitly).`
      );
    }
    return id;
  }

  async submitAnswer(request: SubmitAnswerRequest): Promise<SubmitAnswerResponse> {
    const sessionId = this.resolveVoiceSessionId(request.sessionId);
    const testmode = request.testmode ?? this.defaultTestMode;

    const endpoint = `/api/${this.apiVersion}/voice-sessions/${sessionId}/submit?testmode=${testmode}`;
    const url = `${this.baseUrl}${endpoint}`;

    const extraHeaders = await resolveHeaders(this.headers);
    const { signal, cancel } = withTimeoutSignal(this.timeoutMs);

    try {
      const form = new FormData();

      // ✅ bỏ childId
      const fileName =
        typeof (request.audioFile as any)?.name === "string" ? (request.audioFile as any).name : "audio.wav";
      form.append("audio_file", request.audioFile, fileName);

      form.append("questionIndex", String(request.questionIndex));
      form.append(
        "targetText",
        typeof request.targetText === "string" ? request.targetText : JSON.stringify(request.targetText)
      );
      form.append("durationMs", String(request.durationMs));
      form.append("exercise_type", request.exerciseType);

      const res = await fetch(url, {
        method: "POST",
        headers: { ...extraHeaders },
        body: form,
        signal,
      });

      if (!res.ok) {
        const err = await safeReadErrorDetail(res);
        throw new VoiceApiError({
          status: res.status,
          endpoint,
          detail: err.detail,
          message: `Submit answer failed (${res.status})${err.detail ? `: ${err.detail}` : ""}`,
        });
      }

      return (await res.json()) as SubmitAnswerResponse;
    } finally {
      cancel();
    }
  }

  async endSession(request: EndSessionRequest): Promise<EndSessionResponse> {
    const sessionId = this.resolveVoiceSessionId(request.sessionId);
    const testmode = request.testmode ?? this.defaultTestMode;

    const endpoint = `/api/${this.apiVersion}/voice-sessions/${sessionId}/end?testmode=${testmode}`;
    const url = `${this.baseUrl}${endpoint}`;

    const extraHeaders = await resolveHeaders(this.headers);
    const { signal, cancel } = withTimeoutSignal(this.timeoutMs);

    try {
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...extraHeaders,
        },
        body: JSON.stringify({
          sessionId,
          totalQuestionsExpect: request.totalQuestionsExpect,
          isUserAborted: request.isUserAborted,
        }),
        signal,
      });

      if (!res.ok) {
        const err = await safeReadErrorDetail(res);
        throw new VoiceApiError({
          status: res.status,
          endpoint,
          detail: err.detail,
          message: `End session failed (${res.status})${err.detail ? `: ${err.detail}` : ""}`,
        });
      }

      const data = (await res.json()) as EndSessionResponse;

      // optional: kết thúc thì clear luôn
      this.lastVoiceSessionId = null;

      return data;
    } finally {
      cancel();
    }
  }
}

/** default client */
let _defaultClient = new VoiceSessionClient();

export function configureVoiceSessionClient(config: VoiceSessionConfig) {
  _defaultClient = new VoiceSessionClient(config);
}
export function getVoiceSessionClient() {
  return _defaultClient;
}

export async function StartSession(req: StartSessionRequest = {}): Promise<StartSessionResponse> {
  return _defaultClient.startSession(req);
}
export async function Submit(req: SubmitAnswerRequest): Promise<SubmitAnswerResponse> {
  return _defaultClient.submitAnswer(req);
}
export async function EndSession(req: EndSessionRequest): Promise<EndSessionResponse> {
  return _defaultClient.endSession(req);
}

export default VoiceSessionClient;
