// GAME SIDE
import type { GameSdk } from "../../game/gameSdk.v1";

type Resolver = (state: any) => void;

export class StateClient {
  private sdk: GameSdk;
  private pendingLoad: Resolver | null = null;

  constructor(sdk: GameSdk) {
    this.sdk = sdk;
  }

  /** Game xin Hub lưu state */
  save(state: any) {
    this.sdk.requestSave(state);
  }

  /** Game xin Hub trả state */
  load(): Promise<any | null> {
    if (this.pendingLoad) {
      return Promise.reject(new Error("LOAD_ALREADY_PENDING"));
    }

    return new Promise((resolve) => {
      this.pendingLoad = resolve;
      this.sdk.requestLoad();
    });
  }

  /** Hub gọi SET_STATE → game nhận ở đây */
  handleSetState(state: any | null) {
    if (this.pendingLoad) {
      this.pendingLoad(state);
      this.pendingLoad = null;
    }
  }
}
