export class OverlayManager {
  private container: HTMLDivElement;

  constructor() {
    // Tạo container full màn hình, pointer-events: none để click xuyên qua game
    this.container = document.createElement("div");
    this.container.id = "iruka-overlay-layer";
    Object.assign(this.container.style, {
      position: "absolute",
      top: "0",
      left: "0",
      width: "100%",
      height: "100%",
      pointerEvents: "none", // Quan trọng: Để click xuyên qua game lúc bình thường
      zIndex: "9999",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
    });
    document.body.appendChild(this.container);
  }

  public showLoading() {
    this.container.innerHTML = `<div class="spinner" style="color: white; font-family: sans-serif;">Loading...</div>`;
    this.container.style.pointerEvents = "all"; // Chặn click
    this.container.style.backgroundColor = "rgba(0,0,0,0.8)";
  }

  public hide() {
    this.container.innerHTML = "";
    this.container.style.pointerEvents = "none"; // Cho phép click lại game
    this.container.style.backgroundColor = "transparent";
  }

  public showResult(score: number, stars: number, onRetry: () => void) {
    this.container.style.pointerEvents = "all";
    this.container.style.backgroundColor = "rgba(0,0,0,0.7)";

    // Render UI chuẩn
    this.container.innerHTML = `
      <div class="result-card" style="background: white; padding: 2rem; border-radius: 1rem; text-align: center; font-family: sans-serif; min-width: 300px;">
        <h2 style="margin: 0 0 1rem 0; color: #333;">Game Complete!</h2>
        <div class="stars" style="font-size: 2rem; margin-bottom: 1rem;">${"⭐".repeat(
          stars
        )}</div>
        <h1 style="font-size: 3rem; margin: 0 0 1.5rem 0; color: #4CAF50;">${score} pts</h1>
        <button id="btn-retry" style="padding: 10px 20px; font-size: 1.2rem; cursor: pointer; background: #2196F3; color: white; border: none; border-radius: 4px;">Chơi lại</button>
      </div>
    `;

    document.getElementById("btn-retry")?.addEventListener("click", () => {
      this.hide();
      onRetry();
    });
  }

  public showError(message: string, code?: string) {
    this.container.style.pointerEvents = "all";
    this.container.style.backgroundColor = "rgba(50,0,0,0.9)";

    this.container.innerHTML = `
      <div style="color: white; padding: 20px; text-align: center;">
        <h1 style="color: #ff5252;">Game Error</h1>
        <p style="font-size: 1.2rem;">${message || "Unknown Error"}</p>
        <small style="color: #ccc;">${code || ""}</small>
      </div>
    `;
  }
}
