export type SdkContext = {
  sessionId?: string;   // env.sessionId
  gameId?: string;      // env.gameId
  lessonId?: string;    // env.lessonId
  gameVersion?: string; // env.gameVersion
  sdkVersion?: string;  // env.sdkVersion
  hubOrigin?: string;   // inferred hub origin
};

let _fallback: SdkContext = {};
let _override: SdkContext = {};

function genLocalSessionId(): string {
  // Prefer crypto.randomUUID when available
  const c: any = typeof globalThis !== "undefined" ? (globalThis as any).crypto : undefined;
  if (c?.randomUUID) return `local-${c.randomUUID()}`;

  // Fallback: time + random (good enough for local/dev)
  const t = Date.now().toString(36);
  const r = Math.random().toString(36).slice(2, 10);
  return `local-${t}-${r}`;
}

/**
 * Set fallback context (mock) for standalone/test.
 * Safe in hub too: INIT (override) will win.
 * Auto-generate fallback.sessionId if missing.
 */
export function configureSdkContext(opts: { fallback?: Partial<SdkContext> }) {
  if (!opts.fallback) return;

  _fallback = { ..._fallback, ...opts.fallback };

  // Auto-generate sessionId once if not provided
  if (!_fallback.sessionId) {
    _fallback.sessionId = genLocalSessionId();
  }
}

/** Override context (typically called from Hub INIT handler). */
export function setSdkContext(partial: Partial<SdkContext>) {
  _override = { ..._override, ...partial };
}

/** Always returns merged context: fallback first, then INIT override. */
export function getSdkContext(): SdkContext {
  return { ..._fallback, ..._override };
}

export function resetSdkContext() {
  _fallback = {};
  _override = {};
}
