import Phaser from 'phaser';
import { GameBridge, type LaunchContext } from '@iruka-edu/game-core';

/**
 * Phaser Plugin that exposes Iruka SDK functionality to all scenes
 * Usage in scene: this.iruka.submitResult(100)
 */
export class IrukaPlugin extends Phaser.Plugins.BasePlugin {
  private bridge!: GameBridge;

  constructor(pluginManager: Phaser.Plugins.PluginManager) {
    super(pluginManager);
  }

  /**
   * Called by BaseGame after the game instance is created.
   * Injects the authenticated bridge into the plugin.
   */
  public init(bridge: GameBridge) {
    this.bridge = bridge;
    // Optional: Log to confirm plugin is active
    console.log('[IrukaSDK] 🔌 Phaser Plugin Attached');
  }

  // ==========================================
  // PUBLIC API (For Game Developers)
  // ==========================================

  /**
   * Get the current game context (User profile, Difficulty, Settings, etc.)
   */
  public get context(): LaunchContext {
    if (!this.bridge) {
      console.warn('[IrukaSDK] Accessing context before bridge is ready');
      return {} as any;
    }
    return this.bridge.context;
  }

  /**
   * Submit the final game result.
   * @param score - The score achieved (number).
   * @param stars - (Optional) Star rating (0-3).
   * @param extraData - (Optional) Any custom data for analytics.
   */
  public submitResult(score: number, stars: number = 0, extraData: Record<string, any> = {}) {
    this.bridge.send('EVT:COMPLETE', {
      score,
      completion: 1, // 100% completed
      details: {
        stars,
        ...extraData
      },
      timestamp: Date.now()
    });
  }

  /**
   * Save the current game state (e.g., current level, inventory).
   * @param data - The object to save.
   */
  public saveState(data: Record<string, any>) {
    this.bridge.send('CMD:SAVE_STATE', data);
  }

  /**
   * Request the Hub to play a haptic feedback (if supported).
   */
  public vibrate(duration: number = 200) {
    // Future proofing: Send command to Hub or use Navigator
    if (navigator.vibrate) {
      navigator.vibrate(duration);
    }
  }

  // ==========================================
  // LEGACY API (Backward Compatibility)
  // ==========================================

  /**
   * Submit score to hub
   * @deprecated Use submitResult() instead
   */
  submitScore(score: number, delta?: number) {
    console.warn('[IrukaSDK] submitScore() is deprecated, use submitResult() instead');
    this.bridge.send('EVT:SCORE_UPDATE', {
      score,
      delta,
      timestamp: Date.now()
    });
  }

  /**
   * Submit progress update
   * @deprecated Use bridge directly or submitResult() for final completion
   */
  submitProgress(current: number, total: number) {
    console.warn('[IrukaSDK] submitProgress() is deprecated');
    this.bridge.send('EVT:PROGRESS', {
      current,
      total,
      percentage: current / total,
      timestamp: Date.now()
    });
  }

  /**
   * Complete game with final result
   * @deprecated Use submitResult() instead
   */
  completeGame(result: { score: number; timeMs: number; extras?: any }) {
    console.warn('[IrukaSDK] completeGame() is deprecated, use submitResult() instead');
    this.submitResult(result.score, 0, { timeMs: result.timeMs, ...result.extras });
  }

  /**
   * Load saved game state
   * @deprecated Use saveState() instead
   */
  async loadState() {
    console.warn('[IrukaSDK] loadState() is deprecated');
    this.bridge.send('CMD:REQUEST_LOAD');
    return null;
  }

  /**
   * Get launch context (readonly)
   * @deprecated Use context property instead
   */
  getContext() {
    console.warn('[IrukaSDK] getContext() is deprecated, use context property instead');
    return this.context;
  }

  /**
   * Send telemetry event
   * @deprecated Use bridge directly
   */
  track(eventType: string, data?: any) {
    console.warn('[IrukaSDK] track() is deprecated');
    this.bridge.send('EVT:TELEMETRY', {
      eventType,
      data,
      timestamp: Date.now()
    });
  }
}

// Plugin key for registration
export const IRUKA_PLUGIN_KEY = 'IrukaPlugin';

/**
 * Helper to register plugin in Phaser game config
 * Use this in your Phaser game configuration to automatically include the Iruka plugin
 */
export function createIrukaPluginConfig() {
  return {
    key: IRUKA_PLUGIN_KEY,
    plugin: IrukaPlugin,
    start: true,
    mapping: 'iruka'
  };
}

// Type augmentation for Phaser Scene
declare module 'phaser' {
  interface Scene {
    /**
     * Access the Iruka SDK features directly.
     * Use this to submit scores, get user context, etc.
     */
    iruka: IrukaPlugin;
  }
}